#include<bits/stdc++.h>
using namespace std;
long long b[500010];
const long long inf=(1ll<<60)-1;
struct segment_tree
{
    struct node
    {
        long long l,r;
        long long lson,rson;
        long long pre0,pre1,suf0,suf1,ans0,ans1,and0,and1;
        long long tag;
    }t[1500010];
    long long cnt;
    segment_tree():cnt(0){}
    void pushup(node &x,node ls,node rs)
    {
        x.pre1=ls.pre1^(rs.pre1&ls.and0);
        x.suf1=rs.suf1^(ls.suf1&rs.and0);
        x.pre0=ls.pre0^(rs.pre0&ls.and1);
        x.suf0=rs.suf0^(ls.suf0&rs.and1);
        x.ans1=(ls.ans1^rs.ans1^(ls.suf1&rs.pre1));
        x.ans0=(ls.ans0^rs.ans0^(ls.suf0&rs.pre0));
        x.and0=ls.and0&rs.and0;
        x.and1=ls.and1&rs.and1;
    }
    void pushup(long long x)
    {
        pushup(t[x],t[t[x].lson],t[t[x].rson]);
    }
    void Swap(long long &a,long long &b,long long x)
    {
        long long v=(a&x)^(b&x);
        a^=v;
        b^=v;
    }
    void pushxor(long long x,long long v)
    {
        Swap(t[x].pre0,t[x].pre1,v);
        Swap(t[x].suf0,t[x].suf1,v);
        Swap(t[x].ans0,t[x].ans1,v);
        Swap(t[x].and0,t[x].and1,v);
        t[x].tag^=v;
    }
    void pushdown(long long x)
    {
        if(t[x].tag)
        {
            pushxor(t[x].lson,t[x].tag);
            pushxor(t[x].rson,t[x].tag);
            t[x].tag=0;
        }
    }
    long long init(long long l,long long r)
    {
        long long x=++cnt;
        t[x].l=l;
        t[x].r=r;
        t[x].tag=0;
        if(l==r)
        {
            t[x].pre0=t[x].suf0=t[x].ans0=t[x].and1=b[l]^inf;
            t[x].pre1=t[x].suf1=t[x].ans1=t[x].and0=b[l];
            return x;
        }
        long long mid=(l+r)>>1;
        t[x].lson=init(l,mid);
        t[x].rson=init(mid+1,r);
        pushup(x);
        return x;
    }
    void update(long long x,long long l,long long r,long long v)
    {
        if(t[x].l>r||t[x].r<l)
        {
            return;
        }
        if(l<=t[x].l&&t[x].r<=r)
        {
            pushxor(x,v);
            return;
        }
        pushdown(x);
        update(t[x].lson,l,r,v);
        update(t[x].rson,l,r,v);
        pushup(x);
    }
    node query(long long x,long long l,long long r)
    {
        if(l<=t[x].l&&t[x].r<=r)
        {
            return t[x];
        }
        pushdown(x);
        long long mid=(t[x].l+t[x].r)>>1;
        if(l<=mid&&r>mid)
        {
            node ans=t[x];
            pushup(ans,query(t[x].lson,l,r),query(t[x].rson,l,r));
            return ans;
        }
        else if(l<=mid)
        {
            return query(t[x].lson,l,r);
        }
        else
        {
            return query(t[x].rson,l,r);
        }
    }
}t;
int main()
{
    long long n,q;
    scanf("%lld%lld",&n,&q);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&b[i]);
        b[i]^=inf;
    }
    t.init(1,n);
    while(q--)
    {
        long long op,x,y;
        scanf("%lld%lld%lld",&op,&x,&y);
        if(op==1)
        {
            long long z;
            scanf("%lld",&z);
            t.update(1,x,y,z);
        }
        else
        {
            long long v=0;
            if(((y-x+1)*(y-x+2)/2)%2==1)
            {
                v=inf;
            }
            printf("%lld\n",t.query(1,x,y).ans1^v);
        }
    }
    return 0;
}
